INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b43b7bbb-bdf8-4593-ae47-fc0fabb4e673',
  '00000000-0000-0000-0000-000000000001',
  $escape$Wireshark for Pentesters: Reconnaissance to Reporting$escape$,
  $escape$Wireshark's protocol analysis capabilities make it an indispensable tool for pentesters. To create a comprehensive attack plan, begin with reconnaissance using the 'Follow TCP Stream' feature to capture and analyze network traffic. Next, use the 'TShark' command-line interface to perform network scanning and identify potential vulnerabilities. Once a vulnerability is identified, use Wireshark's capture filtering to isolate the traffic related to the exploit. Following exploitation, leverage Wireshark's 'Posture Analysis' feature to analyze the system's behavior and identify post-exploitation opportunities. Finally, document all findings and evidence in a detailed report using Wireshark's 'Packet Details' window.$escape$,
  NULL,
  NULL,
