INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2a7b6a3e-edef-4bc0-8fef-5a8a48a60853',
  '00000000-0000-0000-0000-000000000001',
  $escape$Wireshark Post-Exploitation Essentials: Privilege Escalation to Lateral Movement$escape$,
  $escape$Wireshark's 'Follow TCP Stream' feature allows you to analyze protocol exchange in real-time. To identify potential post-exploitation techniques, look for TCP packets with flags 'P' (push) and 'A' (urgent). This indicates data is being pushed or sent with high priority, often used in privilege escalation attacks. Analyze the HTTP request headers for suspicious patterns like 'Authorization: Bearer <token>' or unusual request methods like 'TRACE' or 'CONNECT'.$escape$,
  NULL,
  NULL,
