INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '87cd83a5-9a71-4bb0-808f-15afcab8be3d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Wireshark — Streamlining Packet Capture and Analysis$escape$,
  $escape$To capture a specific TCP conversation in Wireshark, apply a display filter like `tcp.port eq 80 and ip.src eq 192.168.1.100`. This filter displays only TCP packets with the source IP address of 192.168.1.100 and a destination port of 80. Use the `Follow Stream` feature to inspect the captured traffic. Analyze the protocol dissection with the `Protocol Hierarchy` tree view to identify potential security vulnerabilities. Utilize the `TCP Stream Graph` feature to visualize the conversation between the client and server.$escape$,
  NULL,
  NULL,
