INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3c3ed459-b2eb-4b14-8d23-a022207ac1e6',
  '00000000-0000-0000-0000-000000000001',
  $escape$Wireshark — Analyzing Encrypted Traffic with Kali Linux$escape$,
  $escape$When analyzing encrypted traffic with Wireshark, Kali Linux provides a comprehensive toolkit. Start by booting the Kali Linux live image, which includes Wireshark and other security tools. To enable live packet capture, run `tshark -i any -w capture.pcap` in the terminal. For custom builds, use the Kali Linux build scripts to create a tailored environment. To use Kali Linux within WSL2, mount the WSL2 file system to the Kali Linux chroot directory using `sudo mount --bind /mnt/wsl /home/user/kali`.$escape$,
  NULL,
  NULL,
