INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '719537fc-39e1-4c3c-aeaf-3ebc45bb3465',
  '00000000-0000-0000-0000-000000000001',
  $escape$Wireshark Hackery: Unpacking CTF Challenges$escape$,
  $escape$Wireshark's rich feature set makes it an ideal tool for Capture The Flag (CTF) challenges. Familiarize yourself with common categories, such as Steganography, where you'll need to extract hidden data from traffic. Use the 'Follow TCP Stream' feature to analyze encrypted traffic and identify anomalies. In 'Web Exploitation', leverage Wireshark's HTTP dissectors to identify vulnerabilities like SQL injection. For 'Reversing', use the 'Edit -> Preferences -> Protocols -> TCP' settings to customize TCP segmentation and identify potential exploits.$escape$,
  NULL,
  NULL,
