INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd60ce71f-1ecb-4e8a-8ef4-70692180c078',
  '00000000-0000-0000-0000-000000000001',
  $escape$Wireshark for Web App Security: Manual Testing vs Automated Scanners$escape$,
  $escape$When testing web application security using Wireshark, manual inspection of packets is crucial. Use the 'Follow TCP Stream' feature to analyze HTTP requests and responses. Identify potential vulnerabilities like SQL injection and cross-site scripting (XSS) by looking for suspicious query parameters and unescaped user input. Automated scanners like ZAP can also be integrated with Wireshark using the 'ZAP' protocol dissector. However, manual testing provides a deeper understanding of the application's behavior and potential attack vectors.$escape$,
  NULL,
  NULL,
