INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '56588b52-1db1-430b-a999-5bd6c282d41e',
  '00000000-0000-0000-0000-000000000001',
  $escape$Wireshark - Decrypting Passwords with Hashcat$escape$,
  $escape$Wireshark's password protocol dissectors can be configured to use hashcat for password cracking. To achieve this, go to Edit-> Preferences-> Protocols-> Authentication-> Passwords, then select 'Use external password cracker' and choose the hashcat binary. For dictionary attacks, create a hashcat dictionary file and point Wireshark to it using the 'Dictionary' field. For rainbow tables, import the table into hashcat using the '-D' option and reference it in Wireshark. To crack hashes, use the '-m' option to specify the hash type and '-a' for attack mode.$escape$,
  NULL,
  NULL,
